+function isBuiltInToolChoiceError(error: unknown): boolean {
+  if (error instanceof Error) {
+    return error.message.includes(
+      "Function calling config is set without function_declarations",
+    );
+  }
+
+  if (
+    typeof error === "object" &&
+    error !== null &&
+    "message" in error &&
+    typeof error.message === "string"
+  ) {
+    return error.message.includes(
+      "Function calling config is set without function_declarations",
+    );
+  }
+
+  return false;
+}
