+async function resolveGoogleSearchUrl(
+  url: string | undefined,
+): Promise<string | undefined> {
+  if (!url) {
+    return undefined;
+  }
+
+  if (!isGoogleGroundingRedirect(url)) {
+    return url;
+  }
+
+  try {
+    const response = await fetch(url, {
+      method: "HEAD",
+      redirect: "manual",
+    });
+    return response.headers.get("location") || url;
+  } catch {
+    return url;
+  }
+}
